#!/bin/bashset -eecho "=== 实验7：搭建代理服务器 ==="echo "[1/3] 安装 Squid ..."yum install -y squidecho "[2/3] 配置 Squid ..."cp /etc/squid/squid.conf /etc/squid/squid.conf.bak.$(date +%Y%m%d)cat > /etc/squid/squid.conf << 'EOF'acl localnet src 0.0.0.1-0.255.255.255acl localnet src 10.0.0.0/8acl localnet src 172.16.0.0/12acl localnet src 192.168.0.0/16acl localnet src fc00::/7acl localnet src fe80::/10acl SSL_ports port 443acl Safe_ports port 80acl Safe_ports port 21acl Safe_ports port 443acl Safe_ports port 70acl Safe_ports port 210acl Safe_ports port 1025-65535acl Safe_ports port 280acl Safe_ports port 488acl Safe_ports port 591acl Safe_ports port 777http_access deny !Safe_portshttp_access deny CONNECT !SSL_portshttp_access allow localhost managerhttp_access deny managerhttp_access allow localnethttp_access allow localhosthttp_port 8080coredump_dir /var/spool/squidrefresh_pattern ^ftp:           1440    20%     10080refresh_pattern ^gopher:        1440    0%      1440refresh_pattern -i (/cgi-bin/|\?) 0     0%      0refresh_pattern .               0       20%     4320EOFecho "[3/3] 启动服务 ..."systemctl enable squidsystemctl restart squidecho ""echo "=== 实验7 安装完成 ==="echo "测试: curl -x http://localhost:8080 http://www.baidu.com"